// 10% chance of anomaly for testing
var anomaly = Math.random() < 0.1;

var temp      = anomaly ? 60 + Math.random() * 15 : 15 + Math.random() * 25;
var humidity  = anomaly ? 94 + Math.random() * 6  : 30 + Math.random() * 50;
var windSpeed = anomaly ? 40 + Math.random() * 20 : Math.random() * 25;

msg.payload = JSON.stringify({
    temperature: parseFloat(temp.toFixed(2)),
    humidity:    parseFloat(humidity.toFixed(2)),
    wind_speed:  parseFloat(windSpeed.toFixed(2)),
    device_id:   'sensor-001',
    timestamp:   new Date().toISOString()
});
return msg;

var sensor = (typeof msg.payload === 'string') ? JSON.parse(msg.payload) : msg.payload;

msg.originalData = sensor;
msg.payload = { temperature: sensor.temperature, humidity: sensor.humidity, wind_speed: sensor.wind_speed };
msg.headers = { 'Content-Type': 'application/json' };
return msg;

var ml = msg.payload;
var d  = msg.originalData;

// Build InfluxDB Line Protocol string
var tags   = 'device_id=' + d.device_id;
var fields = 'temperature=' + d.temperature + ',humidity=' + d.humidity + ',wind_speed=' + d.wind_speed + ',anomaly=' + (ml.anomaly ? '1.0' : '0.0') + ',score=' + ml.score;
var ts     = Date.now() * 1000000; // nanoseconds

msg.payload = 'environment_metrics,' + tags + ' ' + fields + ' ' + ts;
msg.headers = { 'Authorization': 'Token my-super-secret-token', 'Content-Type': 'text/plain' };

node.status({ fill: ml.anomaly ? 'red' : 'green', shape: 'dot', text: ml.anomaly ? 'ANOMALY' : 'Normal' });
return msg;
